// Build a Discord webhook embed from a normalized notification request.
// Input item shape:
//   { level: 'info'|'hot'|'error', pipeline: 'loomless'|'jv'|'terminator'|'fb_router',
//     message: 'string', fields?: { key: value, ... } }
const EMOJI = { info: 'ℹ️', hot: '🔥', error: '❌' };
const COLOR = { info: 0x3498db, hot: 0xe67e22, error: 0xe74c3c };

const webhookUrl = $env.DISCORD_WEBHOOK_OPS61_FEED;
if (!webhookUrl) {
  throw new Error('Sub_NotifyDiscord: env var DISCORD_WEBHOOK_OPS61_FEED is not set on this n8n instance');
}

const out = [];
for (const item of $input.all()) {
  const d = item.json || {};
  const level = String(d.level || 'info').toLowerCase();
  const emoji = EMOJI[level] || EMOJI.info;
  const color = COLOR[level] || COLOR.info;
  const pipeline = d.pipeline || 'unknown';
  const message = d.message || '';

  const fields =
    d.fields && typeof d.fields === 'object'
      ? Object.entries(d.fields).map(([name, value]) => ({
          name: String(name).slice(0, 256),
          value: String(value).slice(0, 1024) || '\u200b',
          inline: true,
        }))
      : [];

  const embed = {
    title: `${emoji} [${pipeline}] ${message}`.slice(0, 256),
    color,
    fields,
    footer: { text: 'OPS-61' },
    timestamp: new Date().toISOString(),
  };

  out.push({ json: { webhookUrl, payload: { embeds: [embed] } } });
}
return out;
